// Parse RSS/Atom and return entries from last 24h
const competitor = $('Split per Competitor').item.json;
const raw = $input.first().json.data || $input.first().json;
const text = typeof raw === 'string' ? raw : String(raw);

const yesterday = Date.now() - 24 * 60 * 60 * 1000;
const entries = [];

// Atom <entry>
const atomEntryRe = /<entry>([\s\S]*?)<\/entry>/g;
let m;
while ((m = atomEntryRe.exec(text)) !== null) {
  const block = m[1];
  const title = (block.match(/<title[^>]*>([\s\S]*?)<\/title>/) || [])[1]?.trim();
  const link = (block.match(/<link[^>]*href="([^"]+)"/) || [])[1];
  const id = (block.match(/<id>([\s\S]*?)<\/id>/) || [])[1]?.trim();
  const updated = (block.match(/<(updated|published)>([\s\S]*?)<\/(updated|published)>/) || [])[2]?.trim();
  if (!title) continue;
  const ts = updated ? new Date(updated).getTime() : Date.now();
  if (ts < yesterday) continue;
  entries.push({ title: title.replace(/<!\[CDATA\[|\]\]>/g, ''), link, external_id: id || link, captured_at: updated });
}

// RSS 2.0 <item>
const rssItemRe = /<item>([\s\S]*?)<\/item>/g;
while ((m = rssItemRe.exec(text)) !== null) {
  const block = m[1];
  const title = (block.match(/<title[^>]*>([\s\S]*?)<\/title>/) || [])[1]?.trim();
  const link = (block.match(/<link[^>]*>([\s\S]*?)<\/link>/) || [])[1]?.trim();
  const guid = (block.match(/<guid[^>]*>([\s\S]*?)<\/guid>/) || [])[1]?.trim();
  const pubDate = (block.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || [])[1]?.trim();
  if (!title) continue;
  const ts = pubDate ? new Date(pubDate).getTime() : Date.now();
  if (ts < yesterday) continue;
  entries.push({ title: title.replace(/<!\[CDATA\[|\]\]>/g, ''), link, external_id: guid || link, captured_at: pubDate });
}

return entries.map(e => ({
  json: {
    competitor: competitor.name,
    source: 'blog',
    raw_payload: e.title,
    source_url: e.link,
    external_id: e.external_id,
    captured_at: e.captured_at,
  }
}));

// Extract visible text from HTML and compute hash
const competitor = $('Split per Competitor').item.json;
const raw = $input.first().json.data || $input.first().json;
const html = typeof raw === 'string' ? raw : String(raw);

// Strip scripts/styles, then tags
const stripped = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Simple hash (FNV-1a 32-bit, hex)
function hash(s) {
  let h = 0x811c9dc5;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = (h * 0x01000193) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
}

return [{
  json: {
    competitor: competitor.name,
    source: 'pricing',
    raw_payload: stripped.slice(0, 4000),
    source_url: competitor.pricing_url,
    external_id: `${competitor.name}-pricing`,
    snapshot_hash: hash(stripped),
    captured_at: new Date().toISOString(),
  }
}];

// Skip if no meta_page_id configured
const competitor = $('Split per Competitor').item.json;
if (!competitor.meta_page_id) return [];

const raw = $input.first().json;
const ads = raw?.data || [];
const yesterday = Date.now() - 24 * 60 * 60 * 1000;

return ads
  .filter(a => a.ad_creation_time && new Date(a.ad_creation_time).getTime() > yesterday)
  .map(a => ({
    json: {
      competitor: competitor.name,
      source: 'meta_ads',
      raw_payload: `${(a.ad_creative_link_titles || []).join(' | ')}\n\n${(a.ad_creative_bodies || []).join('\n---\n').slice(0, 2000)}`,
      source_url: a.ad_snapshot_url || '',
      external_id: a.id,
      captured_at: a.ad_creation_time,
    }
  }));

// Decide whether to analyze:
// - blog/meta_ads: skip if external_id already exists (already processed)
// - pricing: process if hash differs from previous snapshot
const current = $('Merge per Competitor').item.json;
const prev = $json;
const prevExists = !!prev.id;

let changed = false;
let prevText = '';

if (current.source === 'pricing') {
  if (!prevExists) {
    changed = true; // first time, store snapshot
  } else {
    const prevHashProp = prev.properties?.snapshot_hash?.rich_text?.[0]?.plain_text || '';
    if (prevHashProp !== current.snapshot_hash) {
      changed = true;
      prevText = prev.properties?.raw_payload?.rich_text?.[0]?.plain_text || '';
    }
  }
} else {
  // blog or meta_ads: external_id-based dedup
  changed = !prevExists;
}

if (!changed) return [];
return [{ json: { ...current, prev_text: prevText, is_first_snapshot: !prevExists } }];

