// Parse LLM output, build 2 rows (snapshot + change) for pricing, 1 row (change) for blog/ads
const raw = $json.message?.content?.[0]?.text || $json.content || $json.text;
let analysis;
try {
  analysis = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
} catch (e) {
  return [];
}

const ctx = $('Detect Real Change').item.json;
const now = new Date().toISOString();
const rows = [];

// CHANGE row (skip if first_snapshot for pricing — only store snapshot)
if (ctx.source !== 'pricing' || !ctx.is_first_snapshot) {
  rows.push({
    json: {
      row_type: 'change',
      title: `${ctx.competitor}: ${ctx.source} — ${analysis.summary.slice(0, 30)}`,
      competitor: ctx.competitor,
      source: ctx.source,
      entry_type: 'change',
      external_id: ctx.external_id + '-' + Date.now(),
      source_url: ctx.source_url,
      captured_at: now,
      summary: analysis.summary,
      category: analysis.category,
      impact_score: analysis.impact_score,
      our_action: analysis.our_action,
      raw_payload: ctx.raw_payload?.slice(0, 1800) || '',
      snapshot_hash: ctx.snapshot_hash || '',
      reasoning: analysis.reasoning,
    }
  });
}

// SNAPSHOT row (pricing only, always update on change)
if (ctx.source === 'pricing') {
  rows.push({
    json: {
      row_type: 'snapshot',
      title: `${ctx.competitor}: pricing snapshot ${now.slice(0, 10)}`,
      competitor: ctx.competitor,
      source: 'pricing',
      entry_type: 'snapshot',
      external_id: ctx.external_id,
      source_url: ctx.source_url,
      captured_at: now,
      summary: 'Latest pricing page snapshot',
      category: 'pricing',
      impact_score: 0,
      our_action: '',
      raw_payload: ctx.raw_payload?.slice(0, 1800) || '',
      snapshot_hash: ctx.snapshot_hash,
      reasoning: '',
    }
  });
}

return rows;

const i = $json;
const impactEmoji = i.impact_score >= 7 ? '🚨' : i.impact_score >= 4 ? '⚠️' : 'ℹ️';

const text = `${impactEmoji} *${i.competitor}* / ${i.source} (impact ${i.impact_score}/10)\n` +
  `*${i.category}*\n` +
  `${i.summary}\n\n` +
  `*우리 액션*: ${i.our_action || '—'}\n` +
  (i.source_url ? `<${i.source_url}|원본 보기>` : '');

return [{ json: { text } }];
